VALUES
  ('social-worker-moex-00781', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年是從兒童期過渡至成年期的重要階段，有關 Erikson 對此階段提出的主張，下列敘述何者 錯誤？', '["青春期的發展任務統稱為自我認同與認同混淆", "同儕朋友是青少年階段的重要關係", "職涯志向不是自我認同的一部分", "此階段發展任務若失敗，將導致角色混亂，生活缺乏目的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00782', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於成年晚期的發展任務，下列敘述何者錯誤？', '["Erikson認為是統整對絕望", "統整是指能融合過往的經驗，接受自己的生命歷程", "懷舊是長者維持自我概念的重要方式", "考量到優勢觀點，應鼓勵所有的老人追求健康與獨立生活"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00783', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '電視和 3C 設備使得現代人像住在「繭」裡面，成為被動的消費者，弱化人與人之間的互動。這 樣的社會關係沒落、社會網絡萎縮、公民和政治參與的下降情況，符合下列那一種概念的敘述？', '["社會距離的緊密", "社會資本的衰退", "社會連結的複雜", "社會民主的強化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00784', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列與青春期相關之發展理論的敘述，何者錯誤？', '["Erikson認為青春期的主要任務是親密關係的建立", "青春期是發展自我概念的重要時期", "Piaget認為青少年會關心未來計畫，思考事情的可能性是形式運思期特質的展現", "青少年的道德選擇有從眾的傾向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00785', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童因父母離婚而出現的問題，包括自尊心低落、學業問題、行為問題等。如何幫助孩子有更好 的適應，下列敘述何者錯誤？', '["以開放及尊重的方式與孩子溝通", "及早確認監護權歸屬", "確保孩子了解父母離婚的原因與他們無關", "日常生活儘量保持與原來一致"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00786', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '個體內在心理對於自己是男性、女性或同時包含二者的自我概念，屬於下列何者？', '["性別認同（genderidentity）", "性取向（sexualorientation）", "性別偏見（sexualdiscrimination）", "性別多樣化（sexualdiversity）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00787', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '由於青少年期是發生性霸凌的高峰，因此社會工作者有必要對性霸凌保持高敏感度。下列何者不 是性霸凌行為？', '["女性身體發育因較男性早，容易遭到具性暗示的表演戲謔", "國中男同學間出現的刷卡、阿魯巴或被嘲諷不夠陽剛", "透過肢體行為欺負他人，如用肢體對他人毆打、掐脖子", "非經他人同意以文字描述性交過程，並發布在社群網站"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00788', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '不少母親在COVID-19疫情期間承擔學童網路課程或工時縮減等窘境，落入隱性勞動工作價值被', '["鼓勵企業調整或增 加彈性工時", "盡速研擬學校恢復實體授課的方案", "提供到宅兒童課後輔導服務", "鼓勵雇 主支持員工申請防疫照顧假"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00789', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Tavris與Wade（1984）曾提出「家庭主婦症候群」此一社會現象，有關這些家庭主婦的描述，下 列何者錯誤？', '["因長期在家缺乏運動，容易有肥胖與高血壓等症候群", "社交上比較孤立，想建立有意義的社會連結也不容易", "社會較不重視此角色的價值，使其家庭地位較顯低落", "與單身職業婦女相比，她們較不快樂且易自我批評"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00790', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Troiden（1989）的LGBT青少年認同感調適歷程，當青少年已重新架構其社交生活，並正向 和穩定的連結到與同類人所組成的社群時，象徵已進入那個階段？', '["「敏感化」階段", "「認同混淆」階段", "「認同採取」階段", "「承諾」階段"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
